import java.util.*;

class CombinationIterator {

    private List<String> combinations;
    private int index;

    public CombinationIterator(String characters, int combinationLength) {
        combinations = new ArrayList<>();
        backtrack(characters, combinationLength, 0, new StringBuilder(), combinations);
        index = 0;
    }

    public String next() {
        return combinations.get(index++);
    }

    public boolean hasNext() {
        return index < combinations.size();
    }

    private void backtrack(String characters, int combinationLength, int start, StringBuilder current, List<String> combinations) {
        if (current.length() == combinationLength) {
            combinations.add(current.toString());
            return;
        }
        for (int i = start; i <= characters.length() - (combinationLength - current.length()); i++) {
            current.append(characters.charAt(i));
            backtrack(characters, combinationLength, i + 1, current, combinations);
            current.deleteCharAt(current.length() - 1);
        }
    }
}
